import {{ Injectable }} from '@nestjs/common';
import {{ PaymentService }} from './models/payment.model';
import {{ PaymentServiceRepository }} from './repositories/payment.repository';

@Injectable()
export class PaymentServiceService {{
  constructor(
    private readonly repository: PaymentServiceRepository,
  ) {{}}

  async findAll(): Promise<PaymentService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<PaymentService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<PaymentService>): Promise<PaymentService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<PaymentService>): Promise<PaymentService> {{
    return this.repository.update(id, data);
  }}
}}

